  1	/**
  2	 * useWebSocket Hook
  3	 * React hook for WebSocket connections with automatic reconnection
  4	 */
  5	import { useEffect, useRef, useState, useCallback } from 'react';
  6	import {
  7	  WebSocketEvent,
  8	  WebSocketEventType,
  9	  ConnectionStatus,
 10	  WebSocketOptions,
 11	  OrderStatus,
 12	  LocationData,
 13	  RoomType,
 14	  OrderWithRealtime,
 15	  NotificationData,
 16	  NotificationType,
 17	} from '../types/websocket';
 18	import { websocketService } from '../services/websocket';
 19	
 20	/**
 21	 * Options for useWebSocket hook
 22	 */
 23	export interface UseWebSocketOptions extends WebSocketOptions {
 24	  autoConnect?: boolean;
 25	  endpoint?: string;
 26	}
 27	
 28	/**
 29	 * Return type for useWebSocket hook
 30	 */
 31	export interface UseWebSocketReturn {
 32	  // Connection state
 33	  status: ConnectionStatus;
 34	  isConnected: boolean;
 35	  isConnecting: boolean;
 36	  error: Error | null;
 37	
 38	  // Actions
 39	  connect: () => Promise<void>;
 40	  disconnect: () => void;
 41	  send: (message: Partial<WebSocketEvent>) => boolean;
 42	  subscribe: (roomType: RoomType, roomId: string, isOwner?: boolean) => void;
 43	  unsubscribe: (roomType: RoomType, roomId: string) => void;
 44	
 45	  // Event registration
 46	  on: (type: string, handler: (event: WebSocketEvent) => void) => () => void;
 47	  off: (type: string, handler: (event: WebSocketEvent) => void) => void;
 48	}
 49	
 50	/**
 51	 * Hook for general WebSocket connection
 52	 */
 53	export function useWebSocket(options: UseWebSocketOptions = {}): UseWebSocketReturn {
 54	  const { autoConnect = false, endpoint = '/ws', ...wsOptions } = options;
 55	  
 56	  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
 57	  const [error, setError] = useState<Error | null>(null);
 58	  const handlersRef = useRef<Array<{ type: string; handler: (event: WebSocketEvent) => void }>>([]);
 59	
 60	  const isConnected = status === ConnectionStatus.CONNECTED;
 61	  const isConnecting = status === ConnectionStatus.CONNECTING || status === ConnectionStatus.RECONNECTING;
 62	
 63	  const connect = useCallback(async () => {
 64	    setError(null);
 65	    
 66	    try {
 67	      await websocketService.connect(endpoint, {
 68	        ...wsOptions,
 69	        onConnect: () => {
 70	          setStatus(ConnectionStatus.CONNECTED);
 71	          wsOptions.onConnect?.();
 72	        },
 73	        onDisconnect: () => {
 74	          setStatus(ConnectionStatus.DISCONNECTED);
 75	          wsOptions.onDisconnect?.();
 76	        },
 77	        onError: (err) => {
 78	          setStatus(ConnectionStatus.ERROR);
 79	          setError(err instanceof Error ? err : new Error('WebSocket error'));
 80	          wsOptions.onError?.(err);
 81	        },
 82	        onMessage: wsOptions.onMessage,
 83	      });
 84	    } catch (err) {
 85	      setError(err instanceof Error ? err : new Error('Failed to connect'));
 86	      throw err;
 87	    }
 88	  }, [endpoint, wsOptions]);
 89	
 90	  const disconnect = useCallback(() => {
 91	    websocketService.disconnect();
 92	    setStatus(ConnectionStatus.DISCONNECTED);
 93	  }, []);
 94	
 95	  const send = useCallback((message: Partial<WebSocketEvent>): boolean => {
 96	    return websocketService.send(message);
 97	  }, []);
 98	
 99	  const subscribe = useCallback((roomType: RoomType, roomId: string, isOwner: boolean = false) => {
100	    websocketService.subscribe(roomType, roomId, isOwner);
101	  }, []);
102	
103	  const unsubscribe = useCallback((roomType: RoomType, roomId: string) => {
104	    websocketService.unsubscribe(roomType, roomId);
105	  }, []);
106	
107	  const on = useCallback((type: string, handler: (event: WebSocketEvent) => void): (() => void) => {
108	    handlersRef.current.push({ type, handler });
109	    return websocketService.on(type, handler);
110	  }, []);
111	
112	  const off = useCallback((type: string, handler: (event: WebSocketEvent) => void) => {
113	    handlersRef.current = handlersRef.current.filter(
114	      (h) => h.type !== type || h.handler !== handler
115	    );
116	    websocketService.off(type, handler);
117	  }, []);
118	
119	  // Auto-connect on mount
120	  useEffect(() => {
121	    if (autoConnect) {
122	      connect();
123	    }
124	
125	    // Cleanup on unmount
126	    return () => {
127	      // Only disconnect if we're the only component using the service
128	      // This is a simplification - in production, you'd want reference counting
129	      handlersRef.current.forEach(({ type, handler }) => {
130	        websocketService.off(type, handler);
131	      });
132	    };
133	  }, [autoConnect, connect]);
134	
135	  return {
136	    status,
137	    isConnected,
138	    isConnecting,
139	    error,
140	    connect,
141	    disconnect,
142	    send,
143	    subscribe,
144	    unsubscribe,
145	    on,
146	    off,
147	  };
148	}
