151	 * Hook for tracking a specific order
152	 */
153	export interface UseOrderTrackingOptions {
154	  orderId: string;
155	  onStatusUpdate?: (status: OrderStatus, event: WebSocketEvent) => void;
156	  onLocationUpdate?: (location: LocationData, event: WebSocketEvent) => void;
157	  onDriverAssigned?: (driverId: string, event: WebSocketEvent) => void;
158	  onDeliveryComplete?: (event: WebSocketEvent) => void;
159	  onError?: (error: Error) => void;
160	}
161	
162	export interface UseOrderTrackingReturn {
163	  order: OrderWithRealtime | null;
164	  isConnected: boolean;
165	  isConnecting: boolean;
166	  error: Error | null;
167	  connect: () => Promise<void>;
168	  disconnect: () => void;
169	  requestLocation: () => void;
170	  requestStatus: () => void;
171	}
172	
173	export function useOrderTracking(options: UseOrderTrackingOptions): UseOrderTrackingReturn {
174	  const { 
175	    orderId, 
176	    onStatusUpdate, 
177	    onLocationUpdate, 
178	    onDriverAssigned,
179	    onDeliveryComplete,
180	    onError,
181	  } = options;
182	
183	  const [order, setOrder] = useState<OrderWithRealtime | null>(null);
184	  const [isConnected, setIsConnected] = useState(false);
185	  const [isConnecting, setIsConnecting] = useState(false);
186	  const [error, setError] = useState<Error | null>(null);
187	
188	  const connect = useCallback(async () => {
189	    if (!orderId) return;
190	    
191	    setIsConnecting(true);
192	    setError(null);
193	
194	    try {
195	      await websocketService.trackOrder(orderId, (event) => {
196	        switch (event.type) {
197	          case WebSocketEventType.CONNECTED:
198	            setIsConnected(true);
199	            setIsConnecting(false);
200	            if (event.order) {
201	              setOrder((prev) => ({ ...prev, ...event.order } as OrderWithRealtime));
202	            }
203	            break;
204	
205	          case WebSocketEventType.ORDER_STATUS_UPDATED:
206	            setOrder((prev) => 
207	              prev ? { ...prev, status: event.status, status_history: event.status_history || [] } : null
208	            );
209	            onStatusUpdate?.(event.status, event);
210	            break;
211	
212	          case WebSocketEventType.DRIVER_LOCATION_UPDATE:
213	            if (event.rider_location) {
214	              setOrder((prev) =>
215	                prev ? { ...prev, rider_location: event.rider_location! } : null
216	              );
217	              onLocationUpdate?.(event.rider_location, event);
218	            }
219	            break;
220	
221	          case WebSocketEventType.DRIVER_ASSIGNED:
222	            setOrder((prev) =>
223	              prev ? { 
224	                ...prev, 
225	                rider_id: event.rider_id,
226	                rider_name: event.rider_name,
227	                rider_phone: event.rider_phone,
228	                rider_location: event.rider_location,
229	              } : null
230	            );
231	            onDriverAssigned?.(event.rider_id!, event);
232	            break;
233	
234	          case WebSocketEventType.DELIVERY_COMPLETED:
235	            setOrder((prev) =>
236	              prev ? { ...prev, status: OrderStatus.DELIVERED } : null
237	            );
238	            onDeliveryComplete?.(event);
239	            break;
240	
241	          case WebSocketEventType.ERROR:
242	            setError(new Error(event.message || 'WebSocket error'));
243	            onError?.(new Error(event.message || 'WebSocket error'));
244	            break;
245	        }
246	      });
247	    } catch (err) {
248	      setIsConnecting(false);
249	      setError(err instanceof Error ? err : new Error('Failed to connect'));
250	      onError?.(err instanceof Error ? err : new Error('Failed to connect'));
251	    }
252	  }, [orderId, onStatusUpdate, onLocationUpdate, onDriverAssigned, onDeliveryComplete, onError]);
253	
254	  const disconnect = useCallback(() => {
255	    websocketService.disconnect();
256	    setIsConnected(false);
257	    setOrder(null);
258	  }, []);
259	
260	  const requestLocation = useCallback(() => {
261	    websocketService.requestLocation();
262	  }, []);
263	
264	  const requestStatus = useCallback(() => {
265	    websocketService.requestStatus();
266	  }, []);
267	
268	  // Auto-connect when orderId changes
269	  useEffect(() => {
270	    if (orderId) {
271	      connect();
272	    }
273	    
274	    return () => {
275	      disconnect();
276	    };
277	  }, [orderId]);
278	
279	  return {
280	    order,
281	    isConnected,
282	    isConnecting,
283	    error,
284	    connect,
285	    disconnect,
286	    requestLocation,
287	    requestStatus,
288	  };
289	}
