491	/**
492	 * Hook for user notifications
493	 */
494	export interface UseUserNotificationsOptions {
495	  userId: string;
496	  onNotification?: (event: WebSocketEvent) => void;
497	  onError?: (error: Error) => void;
498	}
499	
500	export interface UseUserNotificationsReturn {
501	  notifications: NotificationData[];
502	  isConnected: boolean;
503	  isConnecting: boolean;
504	  error: Error | null;
505	  connect: () => Promise<void>;
506	  disconnect: () => void;
507	  clearNotifications: () => void;
508	  removeNotification: (id: string) => void;
509	}
510	
511	export function useUserNotifications(options: UseUserNotificationsOptions): UseUserNotificationsReturn {
512	  const { userId, onNotification, onError } = options;
513	
514	  const [notifications, setNotifications] = useState<NotificationData[]>([]);
515	  const [isConnected, setIsConnected] = useState(false);
516	  const [isConnecting, setIsConnecting] = useState(false);
517	  const [error, setError] = useState<Error | null>(null);
518	
519	  const connect = useCallback(async () => {
520	    if (!userId) return;
521	
522	    setIsConnecting(true);
523	    setError(null);
524	
525	    try {
526	      await websocketService.connectAsUser(userId, (event) => {
527	        // Create notification for important events
528	        if (
529	          event.type === WebSocketEventType.DELIVERY_COMPLETED ||
530	          event.type === WebSocketEventType.DRIVER_ASSIGNED ||
531	          event.type === WebSocketEventType.ORDER_STATUS_UPDATED
532	        ) {
533	          const notification: NotificationData = {
534	            id: `${Date.now()}-${Math.random()}`,
535	            type: NotificationType.INFO,
536	            title: getNotificationTitle(event.type),
537	            message: getNotificationMessage(event),
538	            timestamp: Date.now(),
539	            orderId: event.order_id,
540	            autoDismiss: true,
541	            dismissAfter: 5000,
542	          };
543	
544	          setNotifications((prev) => [...prev, notification]);
545	        }
546	
547	        if (event.type === WebSocketEventType.CONNECTED) {
548	          setIsConnected(true);
549	          setIsConnecting(false);
550	        } else if (event.type === WebSocketEventType.ERROR) {
551	          setError(new Error(event.message || 'WebSocket error'));
552	          onError?.(new Error(event.message || 'WebSocket error'));
553	        }
554	
555	        onNotification?.(event);
556	      });
557	    } catch (err) {
558	      setIsConnecting(false);
559	      setError(err instanceof Error ? err : new Error('Failed to connect'));
560	      onError?.(err instanceof Error ? err : new Error('Failed to connect'));
561	    }
562	  }, [userId, onNotification, onError]);
563	
564	  const disconnect = useCallback(() => {
565	    websocketService.disconnect();
566	    setIsConnected(false);
567	  }, []);
568	
569	  const clearNotifications = useCallback(() => {
570	    setNotifications([]);
571	  }, []);
572	
573	  const removeNotification = useCallback((id: string) => {
574	    setNotifications((prev) => prev.filter((n) => n.id !== id));
575	  }, []);
576	
577	  // Auto-connect when userId changes
578	  useEffect(() => {
579	    if (userId) {
580	      connect();
581	    }
582	
583	    return () => {
584	      disconnect();
585	    };
586	  }, [userId]);
587	
588	  // Auto-dismiss notifications
589	  useEffect(() => {
590	    const timers: NodeJS.Timeout[] = [];
591	
592	    notifications.forEach((notification) => {
593	      if (notification.autoDismiss && notification.dismissAfter) {
594	        const timer = setTimeout(() => {
595	          removeNotification(notification.id);
596	        }, notification.dismissAfter);
597	        timers.push(timer);
598	      }
599	    });
600	
601	    return () => {
602	      timers.forEach((timer) => clearTimeout(timer));
603	    };
604	  }, [notifications, removeNotification]);
605	
606	  return {
607	    notifications,
608	    isConnected,
609	    isConnecting,
610	    error,
611	    connect,
612	    disconnect,
613	    clearNotifications,
614	    removeNotification,
615	  };
616	}
617	
618	// Helper functions
619	function getNotificationTitle(eventType: string): string {
620	  switch (eventType) {
621	    case WebSocketEventType.DELIVERY_COMPLETED:
622	      return 'Order Delivered!';
623	    case WebSocketEventType.DRIVER_ASSIGNED:
624	      return 'Driver Assigned';
625	    case WebSocketEventType.ORDER_STATUS_UPDATED:
626	      return 'Order Updated';
627	    default:
628	      return 'Notification';
629	  }
630	}
631	
632	function getNotificationMessage(event: WebSocketEvent): string {
633	  switch (event.type) {
634	    case WebSocketEventType.DELIVERY_COMPLETED:
635	      return 'Your order has been delivered. Enjoy your meal!';
636	    case WebSocketEventType.DRIVER_ASSIGNED:
637	      return `A driver has been assigned to your order.${event.rider_name ? ` Driver: ${event.rider_name}` : ''}`;
638	    case WebSocketEventType.ORDER_STATUS_UPDATED:
639	      return `Your order status has been updated to: ${event.status}`;
640	    default:
641	      return 'You have a new notification';
642	  }
643	}
644	
645	// Re-export types
646	export type {
647	  WebSocketEvent,
648	  WebSocketOptions,
649	  RoomType,
650	  OrderStatus,
651	  LocationData,
652	  OrderWithRealtime,
653	};

