  exclusive_offers: boolean;
  early_access: boolean;
  referral_range: { min: number; max: number | string };
}

export function RewardsPage() {
  const { user } = useAuth();
  const [dashboard, setDashboard] = useState<TierInfo | null>(null);
  const [tiers, setTiers] = useState<TierConfig[]>([]);
  const [loading, setLoading] = useState(true);
  const [copied, setCopied] = useState(false);
  const [activeTab, setActiveTab] = useState<'overview' | 'referrals' | 'history'>('overview');
  const [redeeming, setRedeeming] = useState<string | null>(null);
  const [redeemMessage, setRedeemMessage] = useState<string>('');

  useEffect(() => {
    loadDashboard();
    loadTiers();
  }, []);

  const loadDashboard = async () => {
    try {
      const response = await api.get('/api/v1/customer-rewards/dashboard');
      setDashboard(response.data);
    } catch (error) {
      console.error('Failed to load dashboard:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadTiers = async () => {
    try {
      const response = await api.get('/api/v1/customer-rewards/tiers');
      setTiers(response.data.tiers);
    } catch (error) {
      console.error('Failed to load tiers:', error);
    }
  };

  const copyReferralCode = () => {
    if (dashboard?.referral_code) {
      navigator.clipboard.writeText(dashboard.referral_code);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const shareReferral = async () => {
    const shareText = `Join me on iHhashi and get ${dashboard?.referral_code ? '25 Hashi Coins' : 'rewards'}! Use my code: ${dashboard?.referral_code || 'IH-C-XXXXXX'}. Download the app: https://ihhashi.co.za`;

    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Join iHhashi',
          text: shareText,
          url: `https://ihhashi.co.za/signup?ref=${dashboard?.referral_code || ''}`,
        });
      } catch (error) {
        console.log('Share cancelled');
      }
    } else {
      navigator.clipboard.writeText(shareText);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const redeemReward = async (type: 'free-delivery' | 'discount-15' | 'discount-30') => {
    setRedeeming(type);
    try {
      let response;
      if (type === 'free-delivery') {
        response = await api.post('/api/v1/customer-rewards/redeem/free-delivery');
      } else {
        const amount = type === 'discount-15' ? 15 : 30;
        response = await api.post(`/api/v1/customer-rewards/redeem/discount/${amount}`);
      }

      if (response.data.success) {
        setRedeemMessage(response.data.message);
        loadDashboard(); // Refresh dashboard
      } else {
        setRedeemMessage(response.data.message);
      }
    } catch (error: any) {
      setRedeemMessage(error.response?.data?.detail || 'Failed to redeem');
    } finally {
      setRedeeming(null);
      setTimeout(() => setRedeemMessage(''), 3000);
    }
  };

  const getTierIcon = (tier: string) => {
    switch (tier.toLowerCase()) {
      case 'bronze': return <Medal className="w-6 h-6" style={{ color: '#CD7F32' }} />;
      case 'silver': return <Medal className="w-6 h-6" style={{ color: '#C0C0C0' }} />;
      case 'gold': return <Crown className="w-6 h-6" style={{ color: '#FFD700' }} />;
      case 'platinum': return <Diamond className="w-6 h-6" style={{ color: '#E5E4E2' }} />;
      default: return <Award className="w-6 h-6" />;
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-orange-500"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      {/* Header */}
      <div className="bg-gradient-to-br from-orange-500 to-orange-600 text-white">
        <div className="max-w-4xl mx-auto px-4 py-8">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold">Rewards & Benefits</h1>
              <p className="text-orange-100">Earn Hashi Coins and unlock exclusive perks</p>
            </div>
            <div className="text-center">
              <div className="bg-white/20 backdrop-blur-sm rounded-xl p-3">
                <Coins className="w-8 h-8 mx-auto mb-1" />
                <div className="text-2xl font-bold">{dashboard?.hashi_coins_balance || 0}</div>
                <div className="text-xs text-orange-100">Hashi Coins</div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Tier Progress Card */}
      <div className="max-w-4xl mx-auto px-4 -mt-6">
        <motion.div 
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          className="bg-white rounded-2xl shadow-lg p-6"
        >
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
              {getTierIcon(dashboard?.tier || 'bronze')}
              <div>
                <h2 className="font-bold text-lg">{dashboard?.tier_name || 'Bronze'} Tier</h2>
                <p className="text-sm text-gray-500">
                  {dashboard?.referrals_to_next_tier ? 
                    `${dashboard.referrals_to_next_tier} more referrals to ${dashboard.next_tier}` : 
                    'You\'ve reached the highest tier!'}
                </p>
              </div>
            </div>
            <div className="text-right">
              <div className="text-2xl font-bold text-orange-500">
                {dashboard?.total_referrals || 0}
              </div>
              <div className="text-xs text-gray-500">Referrals</div>
            </div>
          </div>

          {/* Progress Bar */}
          <div className="relative h-3 bg-gray-200 rounded-full overflow-hidden">
            <div className="absolute inset-0 flex">
              <div className={`flex-1 ${dashboard?.tier_progress?.bronze?.achieved ? 'bg-orange-400' : 'bg-gray-300'}`} />
              <div className={`flex-1 ${dashboard?.tier_progress?.silver?.achieved ? 'bg-gray-400' : 'bg-gray-300'}`} />
              <div className={`flex-1 ${dashboard?.tier_progress?.gold?.achieved ? 'bg-yellow-400' : 'bg-gray-300'}`} />
              <div className={`flex-1 ${dashboard?.tier_progress?.platinum?.achieved ? 'bg-purple-400' : 'bg-gray-300'}`} />
            </div>
          </div>
          <div className="flex justify-between text-xs text-gray-500 mt-2">
            <span>Bronze</span>
            <span>Silver</span>
            <span>Gold</span>
            <span>Platinum</span>
          </div>
        </motion.div>
      </div>

      {/* Tabs */}
      <div className="max-w-4xl mx-auto px-4 mt-6">
        <div className="flex gap-2 bg-white p-1 rounded-xl shadow-sm">
          {(['overview', 'referrals', 'history'] as const).map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`flex-1 py-2 px-4 rounded-lg font-medium text-sm transition-colors ${
                activeTab === tab 
                  ? 'bg-orange-500 text-white' 
                  : 'text-gray-600 hover:bg-gray-100'
              }`}
            >
              {tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {/* Tab Content */}
      <div className="max-w-4xl mx-auto px-4 mt-6">
        <AnimatePresence mode="wait">
          {activeTab === 'overview' && (
            <motion.div
              key="overview"
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              className="space-y-4"
            >
              {/* Referral Code Card */}
              <div className="bg-white rounded-xl shadow-sm p-6">
                <h3 className="font-semibold mb-4 flex items-center gap-2">
                  <Share2 className="w-5 h-5 text-orange-500" />
                  Your Referral Code
                </h3>
                <div className="flex items-center gap-3">
                  <div className="flex-1 bg-gray-100 rounded-lg px-4 py-3 font-mono text-lg tracking-wider">
                    {dashboard?.referral_code || 'Loading...'}
                  </div>
                  <button
                    onClick={copyReferralCode}
                    className="p-3 bg-orange-100 text-orange-600 rounded-lg hover:bg-orange-200 transition-colors"
                    title="Copy code"
                  >
                    {copied ? <Check className="w-5 h-5" /> : <Copy className="w-5 h-5" />}
                  </button>
                  <button
                    onClick={shareReferral}
                    className="p-3 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition-colors"
                    title="Share"
                  >
                    <Share2 className="w-5 h-5" />
                  </button>
                </div>
                <p className="text-sm text-gray-500 mt-3">
                  Share your code with friends! You get <strong>50 Hashi Coins</strong>, they get <strong>25 Hashi Coins</strong>!
                </p>
              </div>

              {/* Redeem Rewards */}
              <div className="bg-white rounded-xl shadow-sm p-6">
                <h3 className="font-semibold mb-4 flex items-center gap-2">
                  <Gift className="w-5 h-5 text-orange-500" />
                  Redeem Rewards
                </h3>

                {redeemMessage && (
                  <div className={`mb-4 p-3 rounded-lg ${redeemMessage.includes('success') ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
                    {redeemMessage}
                  </div>
                )}

                <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                  <button
                    onClick={() => redeemReward('free-delivery')}
                    disabled={redeeming === 'free-delivery' || (dashboard?.hashi_coins_balance || 0) < 100}
                    className="p-4 border-2 border-orange-100 rounded-xl hover:border-orange-500 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    <div className="text-2xl mb-2">🚚</div>
                    <div className="font-semibold">Free Delivery</div>
                    <div className="text-sm text-gray-500">100 coins</div>
                  </button>

                  <button
                    onClick={() => redeemReward('discount-15')}
                    disabled={redeeming === 'discount-15' || (dashboard?.hashi_coins_balance || 0) < 150}
                    className="p-4 border-2 border-orange-100 rounded-xl hover:border-orange-500 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    <div className="text-2xl mb-2">💰</div>
                    <div className="font-semibold">R15 Off</div>
                    <div className="text-sm text-gray-500">150 coins</div>
                  </button>

                  <button
                    onClick={() => redeemReward('discount-30')}
                    disabled={redeeming === 'discount-30' || (dashboard?.hashi_coins_balance || 0) < 300}
                    className="p-4 border-2 border-orange-100 rounded-xl hover:border-orange-500 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    <div className="text-2xl mb-2">💎</div>
                    <div className="font-semibold">R30 Off</div>
                    <div className="text-sm text-gray-500">300 coins</div>
                  </button>
                </div>
              </div>

              {/* Current Benefits */}
              <div className="bg-white rounded-xl shadow-sm p-6">
                <h3 className="font-semibold mb-4 flex items-center gap-2">
                  <Award className="w-5 h-5 text-orange-500" />
                  Your Benefits
                </h3>
                <div className="grid grid-cols-2 gap-4">
                  <div className="p-3 bg-orange-50 rounded-lg">
                    <div className="text-2xl font-bold text-orange-600">
                      {dashboard?.tier_benefits?.discount_percent || 5}%
                    </div>
                    <div className="text-sm text-gray-600">Discount on orders</div>
                  </div>
                  <div className="p-3 bg-orange-50 rounded-lg">
                    <div className="text-2xl font-bold text-orange-600">
                      {dashboard?.tier_benefits?.free_deliveries_per_month === -1 ? 
                        '∞' : 
                        dashboard?.tier_benefits?.free_deliveries_per_month || 0}
                    </div>
                    <div className="text-sm text-gray-600">Free deliveries/month</div>
                  </div>
                </div>
                <div className="mt-4 p-3 bg-blue-50 rounded-lg">
                  <div className="flex items-center gap-2 text-blue-700">
                    <TrendingUp className="w-4 h-4" />
                    <span className="font-medium">Support Level:</span>
                    <span>{dashboard?.tier_benefits?.support_level || 'Standard'}</span>
                  </div>
                </div>
              </div>
            </motion.div>
          )}

          {activeTab === 'referrals' && (
            <motion.div
              key="referrals"
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
            >
              <div className="bg-white rounded-xl shadow-sm p-6">
                <h3 className="font-semibold mb-4">How It Works</h3>
                <div className="space-y-4">
                  <div className="flex items-start gap-4">
                    <div className="w-8 h-8 bg-orange-100 rounded-full flex items-center justify-center text-orange-600 font-bold">1</div>
                    <div>
                      <h4 className="font-medium">Share Your Code</h4>
                      <p className="text-sm text-gray-500">Send your unique referral code to friends and family</p>
                    </div>
                  </div>
                  <div className="flex items-start gap-4">
                    <div className="w-8 h-8 bg-orange-100 rounded-full flex items-center justify-center text-orange-600 font-bold">2</div>
                    <div>
                      <h4 className="font-medium">They Sign Up</h4>
                      <p className="text-sm text-gray-500">Your friend creates an account using your code and gets 25 Hashi Coins</p>
                    </div>
                  </div>
                  <div className="flex items-start gap-4">
                    <div className="w-8 h-8 bg-orange-100 rounded-full flex items-center justify-center text-orange-600 font-bold">3</div>
                    <div>
                      <h4 className="font-medium">You Both Win</h4>
                      <p className="text-sm text-gray-500">After their first order, you get 50 Hashi Coins!</p>
                    </div>
                  </div>
                </div>
              </div>
            </motion.div>
          )}

          {activeTab === 'history' && (
            <motion.div
              key="history"
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
            >
              <div className="bg-white rounded-xl shadow-sm p-6">
                <h3 className="font-semibold mb-4">Coin Transaction History</h3>
                {dashboard?.coin_history && dashboard.coin_history.length > 0 ? (
                  <div className="space-y-3">
                    {dashboard.coin_history.map((tx: any) => (
                      <div key={tx.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                        <div>
                          <div className="font-medium">{tx.description}</div>
                          <div className="text-xs text-gray-500">
                            {new Date(tx.date).toLocaleDateString()}
                          </div>
                        </div>
                        <div className={`font-bold ${tx.amount > 0 ? 'text-green-600' : 'text-orange-600'}`}>
                          {tx.amount > 0 ? '+' : ''}{tx.amount}
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-8 text-gray-500">
                    <Coins className="w-12 h-12 mx-auto mb-3 opacity-30" />
                    <p>No transactions yet</p>
                    <p className="text-sm">Start referring friends to earn coins!</p>
                  </div>
                )}
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}
"}
